import path from "path";
import fs from "fs";
import { fileURLToPath } from "url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));

const packageRoot = path.resolve(__dirname, "..");
const isRunAsPackage = fs.existsSync(path.join(packageRoot, "dist"));
const projectRoot = path.resolve(
  process.env.BMAD_PROJECT_ROOT ||
    (isRunAsPackage ? process.cwd() : path.join(packageRoot, "..")),
);

try {
  if (!fs.existsSync(projectRoot) || !fs.statSync(projectRoot).isDirectory()) {
    console.error(`BMAD_PROJECT_ROOT is not a valid directory: ${projectRoot}`);
    process.exit(1);
  }
} catch (_err) {
  console.error(`BMAD_PROJECT_ROOT is not a valid directory: ${projectRoot}`);
  process.exit(1);
}

const bmadRoot = path.join(projectRoot, "_bmad");

export { packageRoot, isRunAsPackage, projectRoot, bmadRoot };
